SELECT MAX(query_time) AS MaxQueryTime
FROM dns_records
WHERE domain_id = 0;

SELECT domain_name
FROM domains
WHERE domain_id NOT IN (SELECT domain_id FROM dns_records);

SELECT 
    (SELECT COUNT(*) FROM dns_records) AS dns_records_count,
    (SELECT COUNT(*) FROM dns_performance) AS dns_performance_count;

SELECT AVG(DISTINCT ping_rtt) 
FROM dns_performance 
WHERE query_time > 50;

SELECT MAX(ping_rtt) AS max_round_trip_time
FROM dns_performance
WHERE record_id = 0;

SELECT description 
FROM optimize_suggestions 
WHERE record_id = 0;

SELECT msg_size
FROM dns_records
WHERE query_time = (
  SELECT MAX(query_time)
  FROM dns_records
  WHERE query_time > (
    SELECT AVG(query_time) 
    FROM dns_records
  )
);

SELECT DISTINCT record_id 
FROM optimize_suggestions 
WHERE suggestion_type = 'optimize_nameserver';
